<?php

declare(strict_types=1);

namespace Drupal\mymodule\Plugin\Block;

use Drupal\core\Block\Attribute\Block as BlockAttribute;
use Drupal\core\Block\BlockBase;
use Drupal\core\Plugin\ContainerFactoryPluginInterface;
use Symfony\Component\DependencyInjection\ContainerInterface;
use Drupal\core\StringTranslation\StringTranslationTrait;

#[BlockAttribute(
  id: 'mymodule_custom_block',
  admin_label: 'My Custom Block',
  category: 'Custom',
)]
class MyCustomBlock extends BlockBase implements ContainerFactoryPluginInterface {

  use StringTranslationTrait;

  protected string $siteName;

  public static function create(ContainerInterface $container, array $configuration, $plugin_id, $plugin_definition) {
    return new static(
      $configuration,
      $plugin_id,
      $plugin_definition,
      $container->get('current_route_match')->getRouteName()
    );
  }

  public function __construct(
    array $configuration,
    $plugin_id,
    $plugin_definition,
    protected readonly string $routeName
  ) {
    parent::__construct($configuration, $plugin_id, $plugin_definition);
  }

  public function build(): array {
    return [
      '#markup' => $this->t('Current route: @route', ['@route' => $this->routeName]),
      '#cache' => [
        'contexts' => ['route'],
      ],
    ];
  }

}
```

**2. key points:**
- `#[Block]` replaces `@Block` docblock annotation (required in PHP 8+).
- Use `ContainerFactoryPluginInterface` + `create()` for DI — *not* `__construct()` with container directly.
- Inject only required services (e.g., `current_route_match` via its service ID).
- Always include cache contexts (`route`, `user`) where appropriate.

This pattern ensures clean DI, type safety, and future-proofing for Drupal 11+.

