```php
<?php

namespace Drupal\mymodule\Plugin\Field\FieldFormatter;

use Drupal\Core\Field\Attribute\FieldFormatter;
use Drupal\Core\Field\FieldItemInterface;
use Drupal\Core\Field\FormatterBase;

#[FieldFormatter(
  id: 'phone_formatted',
  label: @Translation('Formatted Phone (WCAG Compliant)'),
  field_types: {
    'string',
    'telephone',
  },
)]
class PhoneFormattedFormatter extends FormatterBase {

  public function viewElements(FieldItemInterface $item, $langcode): array {
    $phone = $item->value;
    // Normalize phone: remove non-digits
    $digits = preg_replace('/\D+/', '', $phone);

    // Format only if exactly 10 digits
    if (strlen($digits) === 10) {
      $formatted = '(' . substr($digits, 0, 3) . ') ' .
                   substr($digits, 3, 3) . '-' .
                   substr($digits, 6);
    } else {
      $formatted = $phone; // fallback
    }

    return [
      '#markup' => '<span class="phone-formatted" aria-label="Phone number: ' . $formatted . '">' .
                   $formatted .
                   '</span>',
    ];
  }
}
```

