namespace Drupal\mymodule\Plugin\Field\FieldFormatter;

use Drupal\core\Field\Attribute\FieldFormatter as FieldFormatterAttribute;
use Drupal\core\Field\FormatterBase;
use Drupal\core\Field\FieldDefinitionInterface;
use Drupal\core\Plugin\ContainerFactoryPluginInterface;
use Symfony\Component\DependencyInjection\ContainerInterface;
use Drupal\core\StringTranslation\StringTranslationTrait;

#[FieldFormatter(
  id: 'accessible_text_formatter',
  label: 'Accessible Text',
  field_types: {'string', 'string_long'},
)]
class AccessibleTextFormatter extends FormatterBase implements ContainerFactoryPluginInterface {
  use StringTranslationTrait;

  public static function create(ContainerInterface $container, array $configuration, $plugin_id, $plugin_definition) {
    return new static(
      $configuration,
      $plugin_id,
      $plugin_definition,
      $container->get('string_translation')
    );
  }

  public function viewElements(FieldDefinitionInterface $field_definition, $items, $langcode) {
    $elements = [];

    foreach ($items as $delta => $item) {
