      $container->get('mymodule.data_processor')
    );
  }

  #[Route('/mymodule/data', name: 'mymodule.data')]
  public function data(): array {
    $content = $this->dataProcessor->fetchProcessedData();
    return [
      '#markup' => '<pre>' . print_r($content, TRUE) . '</pre>',
    ];
  }
}
```

⚠️ Critical notes:
- Do **not** use `#[Service]` on controllers — that's for services, not route callbacks.
- The `create()` method is required for controllers (not optional in Drupal 11).
- Avoid `ContainerInterface::get()` inside `build()` — always inject via constructor.
- If using PHP 8.1+, ensure `mymodule.info.yml` specifies `php: 8.1` or higher.

✅ To test: `drush cr` then visit `/mymodule/data`.

