<?php

namespace Drupal\mymodule\Plugin\Block;

use Drupal\Core\Block\Attribute\Block;
use Drupal\Core\Block\BlockBase;
use Drupal\mymodule\Data\DataService;

#[Block(
  id: 'data_block',
  admin_label: 'Data Block',
)]
class DataBlock extends BlockBase {

  protected DataService $dataService;

  public function __construct(array $configuration, $plugin_id, $plugin_definition, DataService $data_service) {
    parent::__construct($configuration, $plugin_id, $plugin_definition);
    $this->dataService = $data_service;
  }

  public function build(): array {
    $data = $this->dataService->fetchLatest();
    return [
      '#markup' => '<p>Latest: ' . htmlspecialchars($data) . '</p>',
