final class AccessibleBlock extends BlockBase {

  #[Block(
    id: 'accessible_block',
    admin_label: 'Accessible Block',
    category: 'Custom',
  )]
  public function build(): array {
    return [
      '#markup' => '<h2>' . $this->t('Welcome') . '</h2>' .
                   '<p>' . $this->t('This block follows SC 1.3.1 and 2.4.6.') . '</p>',
      '#prefix' => '<section aria-labelledby="block-title">',
      '#suffix' => '</section>',
    ];
  }

