    $form['heading'] = [
      '#type' => 'textfield',
      '#title' => $this->t('Heading text'),
      '#default_value' => $this->configuration['heading'] ?? '',
      '#required' => TRUE,
    ];
    return $form;
  }

  public function blockSubmit($form, FormStateInterface $form_state): void {
    $this->configuration['heading'] = $form_state->getValue('heading');
