In Drupal 11, define the service in `mymodule.services.yml`, then inject it via the controller’s constructor using `#[Autowired]`. Example:

**mymodule.services.yml:**
```yaml
services:
  mymodule.api_client:
    class: Drupal\mymodule\Service\ApiClient
    arguments: ['@http_client', '@state', '@logger.channel.mymodule']
```

**mymodule/src/Service/ApiClient.php (simplified):**
```php
<?php

namespace Drupal\mymodule\Service;

use GuzzleHttp\ClientInterface;
use Drupal\Core\State\StateInterface;
use Psr\Log\LoggerChannelInterface;

class ApiClient {
  protected ClientInterface $httpClient;
  protected StateInterface $state;
  protected LoggerChannelInterface $logger;

  public function __construct(
    ClientInterface $http_client,
    StateInterface $state,
    LoggerChannelInterface $logger_channel
  ) {
    $this->httpClient = $http_client;
    $this->state = $state;
    $this->logger = $logger_channel;
  }

  public function fetchData(string $endpoint): ?array {
    try {
      $response = $this->httpClient->get($endpoint);
      return json_decode($response->getBody(), TRUE);
    } catch (\Exception $e) {
      $this->logger->error('API fetch failed: @message', ['@message' => $e->getMessage()]);
      return NULL;
    }
  }
}
```

**Controller with injection:**
```php
<?php

namespace Drupal\mymodule\Controller;

use Drupal\Core\Controller\ControllerBase;
use Drupal\mymodule\Service\ApiClient;
use Symfony\Component\DependencyInjection\Attribute\Autowired;

final class DataController extends ControllerBase {

  #[Autowired]
  protected ApiClient $apiClient;

  public function __construct(ApiClient $api_client) {
    $this->apiClient = $api_client;
  }

  public function view(): array {
    $data = $this->apiClient->fetchData('https://api.example.com/data');
    return [
      '#markup' => $data ? '<pre>' . htmlspecialchars(print_r($data, TRUE)) . '</pre>' : $this->t('No data available.'),
    ];
  }
}
```

